import { isSharedCatalogReadOnly } from '../hooks/useSharedCatalog';

/** Khớp BE `ValidationException` — shared catalog guard. */
export const SHARED_CATALOG_EDIT_BLOCKED_MESSAGE =
  'Danh mục dùng chung không sửa trực tiếp. Gửi đề xuất sửa hoặc dùng quyền duyệt (approve).';

export function getSharedCatalogEditBlockedMessage(row: {
  isReadOnly?: boolean;
  scope?: string;
}): string | undefined {
  return isSharedCatalogReadOnly(row) ? SHARED_CATALOG_EDIT_BLOCKED_MESSAGE : undefined;
}
